from agno import Agent
from vex import verify, Policy

filing_policy = Policy(name="court_filing", rules={"citations": "must_be_verifiable"})

@verify(policies=[filing_policy])
def motion_generator(case_details: dict):
    agent = Agent(tools=["pydantic"], output_model="MotionSchema")
    return agent.run(case_details)

motion = motion_generator({"case": "Smith v. Jones"})

from agno import MultimodalAgent
from vex import verify

@verify(policies=["ediscovery_chain_of_custody", "multi_modal_safety"])
def discovery_agent(file_path: str):
    agent = MultimodalAgent(name="eDiscovery", modalities=["image", "audio"])
    return agent.run(f"Analyze: {file_path}")

review = discovery_agent("contract_scan.pdf")
